module counter10bit_up (
    input clk,
    input rst,
    input en,
    output [9:0] q
);

    reg [9:0] obf_q_reg;

    always @(posedge clk or posedge rst) begin
        if (rst)
            obf_q_reg <= 10'b0000000000;
        else if (en)
            obf_q_reg <= obf_q_reg + 1;
    end

    assign q = obf_q_reg;

endmodule
